use regex::Regex;

fn solve(code: Vec<String>, business_line: Vec<String>, is_active: Vec<bool>) -> Vec<String> {
    let valid_business_lines = ["electronics", "grocery", "pharmacy", "restaurant"];
    let business_line_order = |bl: &str| -> usize {
        match bl {
            "electronics" => 0,
            "grocery" => 1,
            "pharmacy" => 2,
            "restaurant" => 3,
            _ => usize::MAX,
        }
    };

    let pattern = Regex::new(r"^[a-zA-Z0-9_]+$").unwrap();
    let mut valid_coupons = Vec::new();

    for i in 0..code.len() {
        if !code[i].is_empty() 
            && pattern.is_match(&code[i]) 
            && valid_business_lines.contains(&business_line[i].as_str()) 
            && is_active[i] {
            valid_coupons.push((business_line[i].clone(), code[i].clone()));
        }
    }

    valid_coupons.sort_by(|a, b| {
        let a_order = business_line_order(&a.0);
        let b_order = business_line_order(&b.0);
        if a_order == b_order {
            a.1.cmp(&b.1)
        } else {
            a_order.cmp(&b_order)
        }
    });

    valid_coupons.into_iter().map(|(_, code)| code).collect()
}
